import { useState, useCallback } from "react";
import { useNavigate, Link } from "react-router-dom";
import api from "../services/api";
import toast from "react-hot-toast";
import { Mail, Lock, Loader2 } from "lucide-react";

import Particles from "@tsparticles/react";
import { loadFull } from "tsparticles";
import Tilt from "react-parallax-tilt";

export default function Login() {

  const navigate = useNavigate();

  const [email,setEmail] = useState("");
  const [password,setPassword] = useState("");
  const [loading,setLoading] = useState(false);

  const particlesInit = useCallback(async (engine) => {
    await loadFull(engine);
  }, []);

  const handleSubmit = async (e) => {

    e.preventDefault();

    if (loading) return;

    try {

      setLoading(true);

      const res = await api.post("/auth/login",{
        email: email.trim().toLowerCase(),
        password
      });

      const { accessToken, refreshToken, user } = res.data;

      localStorage.clear();

      localStorage.setItem("accessToken",accessToken);
      localStorage.setItem("refreshToken",refreshToken);
      localStorage.setItem("user",JSON.stringify(user));

      toast.success("Welcome back 👋");

      navigate("/dashboard",{ replace:true });

    } catch (err) {

      console.error(err);

      toast.error(
        err?.response?.data?.message || "Login failed"
      );

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="min-h-screen animated-bg relative flex items-center justify-center overflow-hidden">

      {/* PARTICLES */}

      <Particles
        id="tsparticles"
        init={particlesInit}
        className="absolute inset-0"
        options={{
          particles: {
            number: { value: 60 },
            size: { value: 3 },
            move: { speed: 0.6 },
            opacity: { value: 0.4 },
            links: {
              enable: true,
              distance: 150,
              color: "#ffffff",
              opacity: 0.15
            }
          }
        }}
      />

      {/* FLOATING BLOBS */}

      <div className="absolute -top-20 -left-20 w-72 h-72 bg-pink-400 rounded-full blur-3xl opacity-40 animate-blob"></div>
      <div className="absolute top-1/3 -right-20 w-72 h-72 bg-blue-400 rounded-full blur-3xl opacity-40 animate-blob animation-delay-2000"></div>
      <div className="absolute bottom-20 left-1/3 w-72 h-72 bg-purple-400 rounded-full blur-3xl opacity-40 animate-blob animation-delay-4000"></div>


      {/* LOGIN CARD WITH 3D TILT */}

      <Tilt
        glareEnable={true}
        glareMaxOpacity={0.25}
        scale={1.05}
        tiltMaxAngleX={10}
        tiltMaxAngleY={10}
        className="relative z-10"
      >

        <form
          onSubmit={handleSubmit}
          className="w-full max-w-md
          bg-white/20 backdrop-blur-xl
          border border-white/30
          rounded-2xl shadow-2xl
          p-8 animate-fadeInUp"
        >

          {/* ANIMATED LOGO */}

          <h1 className="text-4xl font-extrabold text-center mb-6 text-white tracking-wide animate-pulse">
            <span className="text-blue-200">we</span>
            <span className="text-white">FOUND</span>
            <span className="text-green-300">it</span>
          </h1>


          {/* EMAIL FLOATING INPUT */}

          <div className="relative mb-6">

            <Mail className="absolute left-3 top-4 text-white/70" size={18} />

            <input
              type="email"
              required
              value={email}
              onChange={(e)=>setEmail(e.target.value)}
              className="peer w-full pl-10 pt-5 pb-2 rounded-lg
              bg-white/20 text-white placeholder-transparent
              border border-white/30 focus:outline-none focus:ring-2 focus:ring-white/60"
              placeholder="Email"
            />

            <label className="absolute left-10 top-2 text-sm text-white/70
              transition-all peer-placeholder-shown:top-3.5
              peer-placeholder-shown:text-base
              peer-focus:top-2 peer-focus:text-sm">

              Email Address

            </label>

          </div>


          {/* PASSWORD FLOATING INPUT */}

          <div className="relative mb-6">

            <Lock className="absolute left-3 top-4 text-white/70" size={18} />

            <input
              type="password"
              required
              value={password}
              onChange={(e)=>setPassword(e.target.value)}
              className="peer w-full pl-10 pt-5 pb-2 rounded-lg
              bg-white/20 text-white placeholder-transparent
              border border-white/30 focus:outline-none focus:ring-2 focus:ring-white/60"
              placeholder="Password"
            />

            <label className="absolute left-10 top-2 text-sm text-white/70
              transition-all peer-placeholder-shown:top-3.5
              peer-placeholder-shown:text-base
              peer-focus:top-2 peer-focus:text-sm">

              Password

            </label>

          </div>


          {/* BUTTON */}

          <button
            type="submit"
            disabled={loading}
            className="w-full flex items-center justify-center gap-2
            py-2.5 rounded-lg
            bg-white text-indigo-700 font-bold
            hover:bg-indigo-50 transition"
          >

            {loading ? (
              <>
                <Loader2 className="animate-spin" size={18} />
                Logging in...
              </>
            ) : (
              "Login"
            )}

          </button>


          <p className="mt-6 text-center text-white/80 text-sm">

            Don’t have an account?{" "}
            <Link to="/register" className="font-semibold underline">
              Register
            </Link>

          </p>

        </form>

      </Tilt>

    </div>

  );

}
